package com.google.gson.internal;
import java.util.AbstractList;
import java.util.Collection;
import java.util.List;
import java.util.Objects;
import java.util.RandomAccess;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.util.ArrayList;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class NonNullElementWrapperListTest {

  private ArrayList<String> mockDelegate;
  private NonNullElementWrapperList<String> list;

  @BeforeEach
  void setUp() throws Exception {
    mockDelegate = mock(ArrayList.class, withSettings().defaultAnswer(CALLS_REAL_METHODS).name("mockDelegate"));
    list = new NonNullElementWrapperList<>(new ArrayList<>());
    // Inject mockDelegate into list using reflection
    java.lang.reflect.Field delegateField = NonNullElementWrapperList.class.getDeclaredField("delegate");
    delegateField.setAccessible(true);
    delegateField.set(list, mockDelegate);
  }

  @Test
  void equals_SameObject_ReturnsTrue() {
    // equals on delegate with list as argument returns true
    // We cannot mock equals directly, so we spy the delegate instead and override equals behavior
    // But since delegate is mocked, equals is final and cannot be stubbed.
    // So test equals(list) returns true when argument is same object
    assertTrue(list.equals(list));
  }

  @Test
  void equals_NullObject_ReturnsFalse() {
    assertFalse(list.equals(null));
  }

  @Test
  void equals_EqualDelegate_ReturnsTrue() {
    Object other = new Object();
    // Since equals is final and cannot be stubbed on mocks, test actual behavior:
    // delegate.equals(other) returns true if delegate contains other (ArrayList equals)
    // We can spy delegate to override equals
    ArrayList<String> spyDelegate = spy(new ArrayList<>());
    java.lang.reflect.Field delegateField;
    try {
      delegateField = NonNullElementWrapperList.class.getDeclaredField("delegate");
      delegateField.setAccessible(true);
      delegateField.set(list, spyDelegate);
    } catch (Exception e) {
      throw new RuntimeException(e);
    }

    doReturn(true).when(spyDelegate).equals(other);

    assertTrue(list.equals(other));
    verify(spyDelegate).equals(other);
  }

  @Test
  void equals_NotEqualDelegate_ReturnsFalse() {
    Object other = new Object();

    ArrayList<String> spyDelegate = spy(new ArrayList<>());
    java.lang.reflect.Field delegateField;
    try {
      delegateField = NonNullElementWrapperList.class.getDeclaredField("delegate");
      delegateField.setAccessible(true);
      delegateField.set(list, spyDelegate);
    } catch (Exception e) {
      throw new RuntimeException(e);
    }

    doReturn(false).when(spyDelegate).equals(other);

    assertFalse(list.equals(other));
    verify(spyDelegate).equals(other);
  }
}
